  1→/**
  2→ * User Routes for ZeroToShip API
  3→ *
  4→ * Endpoints:
  5→ * - POST /api/v1/user/unsubscribe - Unsubscribe from emails (public, token-based)
  6→ * - GET /api/v1/user/preferences - Get user preferences
  7→ * - PUT /api/v1/user/preferences - Update user preferences
  8→ * - GET /api/v1/user/subscription - Get subscription status
  9→ * - GET /api/v1/user/history - Get viewed/saved ideas
 10→ * - GET /api/v1/user/api-keys - List API keys (Enterprise)
 11→ * - POST /api/v1/user/api-keys - Create API key (Enterprise)
 12→ * - DELETE /api/v1/user/api-keys/:id - Delete API key (Enterprise)
 13→ */
 14→
 15→import { FastifyPluginAsync } from 'fastify';
 16→import { ZodTypeProvider } from 'fastify-type-provider-zod';
 17→import { z } from 'zod';
 18→import { requireAuth, requireEnterprise } from '../middleware/auth';
 19→import { rateLimitMiddleware } from '../middleware/rateLimit';
 20→import {
 21→  getUserPreferences,
 22→  updateUserPreferences,
 23→  getUserSubscription,
 24→  getUserHistory,
 25→  getUserApiKeys,
 26→  createApiKey,
 27→  deleteApiKey,
 28→  deactivateApiKey,
 29→} from '../services/users';
 30→import { getUsageStatus } from '../services/usage';
 31→import type { UserTier } from '../config/tiers';
 32→import {
 33→  UserPreferencesSchema,
 34→  UpdatePreferencesRequestSchema,
 35→  SubscriptionResponseSchema,
 36→  UserHistoryResponseSchema,
 37→  ApiErrorSchema,
 38→} from '../schemas';
 39→
 40→export const userRoutes: FastifyPluginAsync = async (fastify) => {
 41→  const app = fastify.withTypeProvider<ZodTypeProvider>();
 42→
 43→  /**
 44→   * POST /api/v1/user/unsubscribe
 45→   * Unsubscribe a user from emails via token (public — no auth required)
 46→   */
 47→  app.post(
 48→    '/unsubscribe',
 49→    {
 50→      schema: {
 51→        body: z.object({
 52→          token: z.string().uuid(),
 53→        }),
 54→        response: {
 55→          200: z.object({ success: z.boolean(), message: z.string() }),
 56→          404: ApiErrorSchema,
 57→        },
 58→      },
 59→    },
 60→    async (request, reply) => {
 61→      const { token } = request.body;
 62→      const result = await updateUserPreferences(token, { emailFrequency: 'never' });
 63→
 64→      if (!result) {
 65→        return reply.status(404).send({
 66→          code: 'NOT_FOUND',
 67→          message: 'Invalid unsubscribe token',
 68→        });
 69→      }
 70→
 71→      return reply.send({ success: true, message: 'You have been unsubscribed from emails.' });
 72→    }
 73→  );
