203→    { preHandler: [requireAdmin] },
204→    async (request, reply) => {
205→      const [usersResult, subsResult, ideasResult, todayResult, runResult] = await Promise.allSettled([
206→        db.select({ count: count() }).from(users),
207→        db.select({ count: count() }).from(subscriptions).where(eq(subscriptions.status, 'active')),
208→        db.select({ count: count() }).from(ideas),
