233→  /**
234→   * GET /api/v1/admin/runs
235→   * Paginated run history
236→   */
237→  server.get('/runs', { preHandler: [requireAdmin] }, async (request, reply) => {
238→    const query = request.query as { page?: string; limit?: string; status?: string };
239→    const page = Math.max(1, parseInt(query.page || '1'));
240→    const limit = Math.min(100, Math.max(1, parseInt(query.limit || '20')));
241→    const offset = (page - 1) * limit;
242→
243→    // Select all columns except phaseResults (large JSONB)
244→    const runListColumns = {
245→      id: pipelineRuns.id,
246→      runId: pipelineRuns.runId,
247→      status: pipelineRuns.status,
248→      startedAt: pipelineRuns.startedAt,
249→      completedAt: pipelineRuns.completedAt,
250→      config: pipelineRuns.config,
251→      phases: pipelineRuns.phases,
252→      stats: pipelineRuns.stats,
253→      phaseStats: pipelineRuns.phaseStats,
254→      generationMode: pipelineRuns.generationMode,
255→      generationDiagnostics: pipelineRuns.generationDiagnostics,
256→      lastCompletedPhase: pipelineRuns.lastCompletedPhase,
257→      success: pipelineRuns.success,
258→      totalDuration: pipelineRuns.totalDuration,
259→      errors: pipelineRuns.errors,
260→      apiMetrics: pipelineRuns.apiMetrics,
261→      briefSummaries: pipelineRuns.briefSummaries,
262→      updatedAt: pipelineRuns.updatedAt,
263→    };
264→
265→    const statusFilter = query.status === 'completed'
266→      ? eq(pipelineRuns.status, 'completed')
267→      : query.status === 'failed'
268→        ? eq(pipelineRuns.status, 'failed')
269→        : query.status === 'needs_review'
270→          ? eq(pipelineRuns.status, 'needs_review')
271→          : undefined;
272→
273→    const baseQuery = statusFilter
274→      ? db.select(runListColumns).from(pipelineRuns).where(statusFilter)
275→      : db.select(runListColumns).from(pipelineRuns);
276→
277→    const countQuery = statusFilter
278→      ? db.select({ count: count() }).from(pipelineRuns).where(statusFilter)
279→      : db.select({ count: count() }).from(pipelineRuns);
280→
281→    const [runs, totalResult] = await Promise.all([
282→      baseQuery.orderBy(desc(pipelineRuns.startedAt)).limit(limit).offset(offset),
283→      countQuery,
284→    ]);
285→
286→    return reply.send({
287→      runs,
288→      total: totalResult[0]?.count || 0,
289→      page,
290→      limit,
291→    });
292→  });
