306→    return reply.send({ run: result[0] });
307→  });
308→
309→  /**
310→   * POST /api/v1/admin/runs/:runId/publish/approve
311→   * Approve a publish-gated run: publish selected ideas and execute delivery.
312→   */
313→  server.post('/runs/:runId/publish/approve', { preHandler: [requireAdmin] }, async (request, reply) => {
314→    const { runId } = request.params as { runId: string };
315→    const body = request.body as { briefIds?: string[] } | undefined;
316→
317→    const result = await db.select().from(pipelineRuns).where(eq(pipelineRuns.runId, runId)).limit(1);
318→    if (result.length === 0) {
319→      return reply.status(404).send({ code: 'NOT_FOUND', message: 'Run not found' });
320→    }
321→
322→    const run = result[0] as any;
323→    const phaseResults = (run.phaseResults ?? {}) as Record<string, any>;
324→    const generateData = phaseResults.generate as { briefs?: any[] } | undefined;
325→    const briefs = generateData?.briefs as any[] | undefined;
326→
327→    if (!Array.isArray(briefs) || briefs.length === 0) {
328→      return reply.status(400).send({ code: 'NO_BRIEFS', message: 'No generated briefs found for this run' });
329→    }
330→
331→    const requestedIds = Array.isArray(body?.briefIds) ? body!.briefIds.filter(Boolean) : [];
332→    const allowAll = requestedIds.length === 0;
333→
334→    const deliverBriefs = allowAll
335→      ? briefs
336→      : briefs.filter((b) => requestedIds.includes(String(b.id)));
337→
338→    const publishIds = Array.from(new Set(deliverBriefs.map((b) => String(b.id)).filter(Boolean)));
339→
340→    if (publishIds.length > 0) {
341→      await db
342→        .update(ideas)
343→        .set({ isPublished: true, publishedAt: new Date() })
344→        .where(inArray(ideas.id, publishIds));
345→    }
346→
347→    const deliverConfig = (run.config ?? {}) as any;
348→    const deliverResult = await runDeliverPhase(runId, deliverConfig, deliverBriefs);
349→
350→    const phases = { ...(run.phases ?? {}) } as Record<string, string>;
351→    phases.deliver = deliverResult.success ? 'completed' : 'failed';
352→
353→    const phaseStats = { ...(run.phaseStats ?? {}) } as Record<string, any>;
354→    if (deliverResult.data) {
355→      phaseStats.deliver = {
356→        sent: deliverResult.data.sent,
357→        failed: deliverResult.data.failed,
358→        subscriberCount: deliverResult.data.subscriberCount,
359→      };
360→    }
361→
362→    const stats = { ...(run.stats ?? {}) } as Record<string, any>;
363→    if (deliverResult.data) {
364→      stats.emailsSent = deliverResult.data.sent;
365→    }
366→
367→    const history = Array.isArray(phaseResults.publishGateHistory)
368→      ? phaseResults.publishGateHistory.slice(0, 200)
369→      : [];
370→    history.push({
371→      action: 'approve',
372→      by: request.userEmail ?? null,
373→      at: new Date().toISOString(),
374→      briefIds: publishIds,
375→      delivered: deliverResult.success,
376→      deliveredSent: deliverResult.data?.sent ?? 0,
377→    });
378→
379→    phaseResults.publishGateHistory = history;
380→    phaseResults.deliver = deliverResult.data ?? null;
381→
382→    const now = new Date();
383→    const startedAt = run.startedAt ? new Date(run.startedAt) : now;
384→
385→    await db.update(pipelineRuns)
386→      .set({
387→        status: deliverResult.success ? 'completed' : 'failed',
388→        completedAt: now,
389→        updatedAt: now,
390→        phases,
391→        phaseStats,
392→        stats,
393→        success: deliverResult.success,
394→        totalDuration: Math.max(0, Math.round(now.getTime() - startedAt.getTime())),
395→        phaseResults,
396→      })
397→      .where(eq(pipelineRuns.runId, runId));
398→
399→    return reply.send({
400→      status: 'ok',
401→      publishedCount: publishIds.length,
402→      delivered: deliverResult.data ?? null,
403→    });
404→  });
405→
406→  /**
407→   * POST /api/v1/admin/runs/:runId/publish/reject
408→   * Reject a publish-gated run: keep ideas unpublished and finalize run as rejected.
409→   */
410→  server.post('/runs/:runId/publish/reject', { preHandler: [requireAdmin] }, async (request, reply) => {
411→    const { runId } = request.params as { runId: string };
412→    const body = request.body as { reason?: string } | undefined;
413→
414→    const result = await db.select().from(pipelineRuns).where(eq(pipelineRuns.runId, runId)).limit(1);
415→    if (result.length === 0) {
416→      return reply.status(404).send({ code: 'NOT_FOUND', message: 'Run not found' });
417→    }
418→
419→    const run = result[0] as any;
420→    const phaseResults = (run.phaseResults ?? {}) as Record<string, any>;
421→
422→    const history = Array.isArray(phaseResults.publishGateHistory)
423→      ? phaseResults.publishGateHistory.slice(0, 200)
424→      : [];
425→    history.push({
426→      action: 'reject',
427→      by: request.userEmail ?? null,
428→      at: new Date().toISOString(),
429→      reason: body?.reason ?? null,
430→    });
431→    phaseResults.publishGateHistory = history;
432→
433→    const now = new Date();
434→    const startedAt = run.startedAt ? new Date(run.startedAt) : now;
435→
436→    await db.update(pipelineRuns)
437→      .set({
438→        status: 'rejected',
439→        completedAt: now,
440→        updatedAt: now,
441→        success: false,
442→        totalDuration: Math.max(0, Math.round(now.getTime() - startedAt.getTime())),
443→        phaseResults,
444→      })
445→      .where(eq(pipelineRuns.runId, runId));
446→
447→    return reply.send({ status: 'ok' });
448→  });
449→
450→  /**
451→   * GET /api/v1/admin/email-logs
452→   * Paginated email delivery logs
453→   */
454→  server.get('/email-logs', { preHandler: [requireAdmin] }, async (request, reply) => {
455→    const query = request.query as { page?: string; limit?: string; status?: string; runId?: string };
456→    const page = Math.max(1, parseInt(query.page || '1'));
457→    const limit = Math.min(100, Math.max(1, parseInt(query.limit || '20')));
458→    const offset = (page - 1) * limit;
459→
460→    const filters = [];
461→    if (query.status && query.status !== 'all') {
462→      filters.push(eq(emailLogs.status, query.status));
463→    }
464→    if (query.runId) {
465→      filters.push(eq(emailLogs.runId, query.runId));
466→    }
467→
468→    const whereClause = filters.length > 0 ? and(...filters) : undefined;
469→
470→    const baseQuery = whereClause
471→      ? db.select().from(emailLogs).where(whereClause)
472→      : db.select().from(emailLogs);
473→
474→    const countQuery = whereClause
475→      ? db.select({ count: count() }).from(emailLogs).where(whereClause)
476→      : db.select({ count: count() }).from(emailLogs);
477→
478→    const [logs, totalResult] = await Promise.all([
479→      baseQuery.orderBy(desc(emailLogs.sentAt)).limit(limit).offset(offset),
480→      countQuery,
481→    ]);
482→
483→    return reply.send({
484→      logs,
485→      total: totalResult[0]?.count || 0,
486→      page,
487→      limit,
488→    });
489→  });
490→
491→  /**
492→   * POST /api/v1/admin/runs/:runId/delivery/resend
493→   * Resend emails that failed during a specific pipeline run.
494→   */
495→  server.post('/runs/:runId/delivery/resend', { preHandler: [requireAdmin] }, async (request, reply) => {
496→    const { runId } = request.params as { runId: string };
497→
498→    // 1. Load the pipeline run
499→    const runResult = await db.select().from(pipelineRuns).where(eq(pipelineRuns.runId, runId)).limit(1);
500→    if (runResult.length === 0) {
501→      return reply.status(404).send({ code: 'NOT_FOUND', message: 'Run not found' });
502→    }
503→
504→    const run = runResult[0] as Record<string, unknown>;
505→    const phaseResults = (run.phaseResults ?? {}) as Record<string, unknown>;
506→    const generateData = phaseResults.generate as { briefs?: unknown[] } | undefined;
507→    const briefs = generateData?.briefs as Array<Record<string, unknown>> | undefined;
508→
509→    if (!Array.isArray(briefs) || briefs.length === 0) {
510→      return reply.status(400).send({ code: 'NO_BRIEFS', message: 'No generated briefs found for this run' });
511→    }
512→
513→    // 2. Get failed email log entries for this run
514→    const failedLogs = await db
515→      .select({ recipientEmail: emailLogs.recipientEmail, userId: emailLogs.userId })
516→      .from(emailLogs)
517→      .where(and(eq(emailLogs.runId, runId), eq(emailLogs.status, 'failed')));
518→
519→    if (failedLogs.length === 0) {
520→      return reply.send({ resent: 0, failed: 0, total: 0 });
521→    }
522→
523→    // 3. Cross-reference with active subscribers to get tier info
524→    const failedEmails = failedLogs.map((l) => l.recipientEmail);
525→    const failedUserIds = failedLogs.map((l) => l.userId);
526→
527→    const activeSubscribers = await db
528→      .select({
529→        id: users.id,
530→        email: users.email,
531→        tier: subscriptions.plan,
532→      })
533→      .from(users)
534→      .innerJoin(subscriptions, eq(subscriptions.userId, users.id))
535→      .where(
536→        and(
537→          eq(subscriptions.status, 'active'),
538→          inArray(users.id, failedUserIds)
539→        )
540→      );
541→
542→    // Only resend to users whose emails were in the failed set
543→    const subscribers: Subscriber[] = activeSubscribers
544→      .filter((s) => failedEmails.includes(s.email))
545→      .map((s) => ({
546→        id: s.id,
547→        email: s.email,
548→        tier: s.tier as Subscriber['tier'],
549→      }));
550→
551→    if (subscribers.length === 0) {
552→      return reply.send({ resent: 0, failed: 0, total: 0 });
553→    }
554→
555→    // 4. Send emails using safe defaults (concurrency 1, delay 1000ms)
556→    const batchResult = await sendDailyBriefsBatch(subscribers, briefs as never[], {});
557→
558→    // 5. Persist new email_logs rows for retry attempts
559→    try {
560→      const retryLogRows = batchResult.deliveries
561→        .filter((d) => d.status === 'sent' || d.status === 'failed')
562→        .map((delivery) => ({
563→          runId,
564→          userId: delivery.subscriberId,
565→          recipientEmail: delivery.email,
566→          subject: `Your Daily Startup Ideas — ${new Date().toLocaleDateString()} (retry)`,
567→          messageId: delivery.messageId,
568→          status: delivery.status as string,
569→          error: delivery.error || null,
570→          sentAt: delivery.sentAt,
571→        }));
572→
573→      if (retryLogRows.length > 0) {
574→        await db.insert(emailLogs).values(retryLogRows);
575→      }
576→    } catch (logError) {
577→      request.log.warn(
578→        { error: logError instanceof Error ? logError.message : String(logError) },
579→        'Failed to persist retry email logs (non-fatal)'
580→      );
581→    }
582→
583→    return reply.send({
584→      resent: batchResult.sent,
585→      failed: batchResult.failed,
586→      total: batchResult.total,
587→    });
588→  });
589→};
