import {
  db,
  users,
  userPreferences,
  subscriptions,
  savedIdeas,
  viewedIdeas,
  apiKeys,
} from '../db/client';
import type {
  UserPreferences,
  UpdatePreferencesRequest,
  UserHistoryResponse,
  SubscriptionResponse,
  UserTier,
  EffortLevel,
} from '../schemas';
import { generateApiKey, hashApiKey, invalidateTierCache } from '../middleware/auth';
import { sendOnboardingEmail } from '../../delivery/onboarding';
import logger from '../../lib/logger';

/**
 * Generate a cryptographic random unsubscribe token (32 bytes hex = 64 chars)
 */
function generateUnsubscribeToken(): string {
  return randomBytes(32).toString('hex');
}

/**
 * Get user by ID
 */
export async function getUserById(
  userId: string
): Promise<{ id: string; email: string; name: string | null; isAdmin: boolean } | null> {
  const rows = await db.select().from(users).where(eq(users.id, userId)).limit(1);

  if (rows.length === 0) {
    return null;
  }

  return rows[0];
}

/**
 * Get user's tier from their subscription (single source of truth)
 */
export async function getUserTierById(userId: string): Promise<UserTier> {
  const result = await db.select({ plan: subscriptions.plan, status: subscriptions.status })
    .from(subscriptions).where(eq(subscriptions.userId, userId)).limit(1);
  const sub = result[0];
  if (!sub || sub.status !== 'active') return 'free';
  return (sub.plan as UserTier) || 'free';
}

/**
 * Get or create user from Supabase auth
 */
export async function getOrCreateUser(
  id: string,
  email: string,
  name?: string
): Promise<{ id: string; email: string; name: string | null; isAdmin: boolean }> {
  // Try to get existing user
  const existing = await getUserById(id);
  if (existing) {
    return existing;
  }

  // Create new user
  const result = await db
    .insert(users)
    .values({ id, email, name: name || null })
    .returning();

  // Create default preferences
  await db.insert(userPreferences).values({ userId: id });

  // Create default subscription (free tier)
  await db.insert(subscriptions).values({ userId: id, plan: 'free', status: 'active' });

  // Send welcome onboarding email (fire-and-forget, never block signup)
  sendOnboardingEmail(id, 'welcome').catch((err) => {
    logger.error(
      { userId: id, error: err instanceof Error ? err.message : String(err) },
      'Failed to send welcome onboarding email'
    );
  });

  return result[0];
}

/**
 * Get user preferences
 */
export async function getUserPreferences(userId: string): Promise<UserPreferences | null> {
  const rows = await db
    .select()
    .from(userPreferences)
    .where(eq(userPreferences.userId, userId))
    .limit(1);

  if (rows.length === 0) {
    return null;
  }

  const row = rows[0];
  return {
    categories: (row.categories as string[]) || [],
    maxEffort: (row.maxEffort as EffortLevel) || 'quarter',
    emailFrequency: (row.emailFrequency as 'daily' | 'weekly' | 'never') || 'daily',
    minPriorityScore: row.minPriorityScore ? parseFloat(row.minPriorityScore) : undefined,
  };
}

/**
 * Update user preferences
 */
export async function updateUserPreferences(
  userId: string,
  updates: UpdatePreferencesRequest
): Promise<UserPreferences | null> {
  const updateData: Record<string, unknown> = { updatedAt: new Date() };

  if (updates.categories !== undefined) {
    updateData.categories = updates.categories;
  }
  if (updates.maxEffort !== undefined) {
    updateData.maxEffort = updates.maxEffort;
  }
  if (updates.emailFrequency !== undefined) {
    updateData.emailFrequency = updates.emailFrequency;
  }
  if (updates.minPriorityScore != null) {
    updateData.minPriorityScore = String(updates.minPriorityScore);
  }

  // Upsert preferences
  const existing = await db
    .select()
    .from(userPreferences)
    .where(eq(userPreferences.userId, userId))
    .limit(1);

  if (existing.length === 0) {
    await db.insert(userPreferences).values({
      userId,
      ...updateData,
    });
  } else {
    await db
      .update(userPreferences)
      .set(updateData)
      .where(eq(userPreferences.userId, userId));
  }

  return getUserPreferences(userId);
}

/**
