 */
export async function getSavedIdeaIds(userId: string): Promise<string[]> {
  const rows = await db
    .select({ ideaId: savedIdeas.ideaId })
    .from(savedIdeas)
    .where(eq(savedIdeas.userId, userId));

  return rows.map((r) => r.ideaId);
}

